#include "biblia.h"

void Biblia::CarregarNaum(Biblia* b) {
    b->dados[NAUM].nome = wxT("Naum");

    b->dados[NAUM].capitulos[1].versos[1] = wxT("Oráculo acerca de Nínive. Livro da visão de Naum, o elcosita.");
    b->dados[NAUM].capitulos[1].versos[2] = wxT("O Senhor é um Deus zeloso e vingador; o Senhor é vingador e cheio de indignação; o Senhor toma vingança contra os seus adversários, e guarda a ira contra os seus inimigos.");
    b->dados[NAUM].capitulos[1].versos[3] = wxT("O Senhor é tardio em irar-se, e de grande poder, e ao culpado de maneira alguma terá por inocente; o Senhor tem o seu caminho no turbilhão e na tempestade, e as nuvens são o pó dos seus pés.");
    b->dados[NAUM].capitulos[1].versos[4] = wxT("Ele repreende o mar, e o faz secar, e esgota todos os rios; desfalecem Basã e Carmelo, e a flor do Líbano murcha.");
    b->dados[NAUM].capitulos[1].versos[5] = wxT("Os montes tremem perante ele, e os outeiros se derretem; e a terra fica devastada diante dele, sim, o mundo, e todos os que nele habitam.");
    b->dados[NAUM].capitulos[1].versos[6] = wxT("Quem pode manter-se diante do seu furor? e quem pode subsistir diante do ardor da sua ira? a sua cólera se derramou como um fogo, e por ele as rochas são fendidas.");
    b->dados[NAUM].capitulos[1].versos[7] = wxT("O Senhor é bom, uma fortaleza no dia da angústia; e conhece os que nele confiam.");
    b->dados[NAUM].capitulos[1].versos[8] = wxT("E com uma inundação transbordante acabará duma vez com o lugar dela; e até para dentro das trevas perseguirá os seus inimigos.");
    b->dados[NAUM].capitulos[1].versos[9] = wxT("Que é o que projetais vós contra o Senhor? Ele destruirá de vez; não se levantará por duas vezes a angústia.");
    b->dados[NAUM].capitulos[1].versos[10] = wxT("Pois ainda que eles se entrelacem como os espinhos, e se saturem de vinho como bêbados, serão inteiramente consumidos como restolho seco.");
    b->dados[NAUM].capitulos[1].versos[11] = wxT("Não saiu de ti um que maquinava o mal contra o Senhor, aconselhando maldade?");
    b->dados[NAUM].capitulos[1].versos[12] = wxT("Assim diz o Senhor: Por mais intatos que sejam, e por mais numerosos, assim mesmo serão exterminados e passarão. Ainda que te afligi, não te afligirei mais.");
    b->dados[NAUM].capitulos[1].versos[13] = wxT("Mas agora quebrarei o seu jugo de sobre ti, e romperei as tuas cadeias.");
    b->dados[NAUM].capitulos[1].versos[14] = wxT("Contra ti, porém, o Senhor deu ordem que não haja mais linhagem do teu nome; da casa dos teus deuses exterminarei as imagens de escultura e as de fundição; farei o teu sepulcro, porque és vil.");
    b->dados[NAUM].capitulos[1].versos[15] = wxT("Eis sobre os montes os pés do que traz boas novas, do que anuncia a paz! Celebra as tuas festas, ó Judá, cumpre os teus votos, porque o ímpio não tornará mais a passar por ti; ele é inteiramente exterminado.");

    b->dados[NAUM].capitulos[2].versos[1] = wxT("O destruidor sobe contra ti. Guarda tu a fortaleza, vigia o caminho, robustece os lombos, arregimenta bem as tuas forças.");
    b->dados[NAUM].capitulos[2].versos[2] = wxT("Pois o Senhor restaura a excelência de Jacó, qual a excelência de Israel; porque os saqueadores os despojaram e destruíram os seus sarmentos.");
    b->dados[NAUM].capitulos[2].versos[3] = wxT("Os escudos dos seus valentes estão vermelhos, os homens valorosos estão vestidos de escarlate; os carros resplandecem como o aço no dia da sua preparação, e as lanças são brandidas.");
    b->dados[NAUM].capitulos[2].versos[4] = wxT("Os carros andam furiosamente nas ruas; cruzam as praças em todas as direções; parecem como tochas, e correm como os relâmpagos.");
    b->dados[NAUM].capitulos[2].versos[5] = wxT("Ele se lembra dos seus nobres; eles tropeçam na sua marcha; apressam-se para chegar ao muro de cidade, arma-se a manta.");
    b->dados[NAUM].capitulos[2].versos[6] = wxT("As portas dos rios abrem-se, e o palácio está em confusão.");
    b->dados[NAUM].capitulos[2].versos[7] = wxT("E está decretado: ela é despida , e levada cativa; e as suas servas gemem como pombas, batendo em seus peitos.");
    b->dados[NAUM].capitulos[2].versos[8] = wxT("Nínive desde que existe tem sido como um tanque de águas; elas, porém, fogem agora: parai, parai, clama-se; mas ninguém olhara para trás.");
    b->dados[NAUM].capitulos[2].versos[9] = wxT("Saqueai a prata, saqueai o ouro; pois não ha fim dos tesouros; abastança há de todas as coisas preciosas.");
    b->dados[NAUM].capitulos[2].versos[10] = wxT("Ela está vazia, esgotada e devastada; derrete-se o coração, tremem os joelhos, e em todos os lombos há dor; o rosto de todos eles empalidece.");
    b->dados[NAUM].capitulos[2].versos[11] = wxT("Onde está agora o covil dos leões, e a habitação dos leões novos, onde andavam o leão, e a leoa, e o cachorro do leão, sem haver ninguém que os espantasse?");
    b->dados[NAUM].capitulos[2].versos[12] = wxT("O leão arrebatava o que bastava para os seus cachorros, e estrangulava a presa para as suas leoas, e enchia de presas as suas cavernas, e de rapina os seus covis.");
    b->dados[NAUM].capitulos[2].versos[13] = wxT("Eis que eu estou contra ti, diz o Senhor dos exércitos, e queimarei na fumaça os teus carros, e a espada devorará os teus leões novos; e exterminarei da terra a tua presa; e não se ouvira mais a voz dos teus embaixadores.");

    b->dados[NAUM].capitulos[3].versos[1] = wxT("Ai da cidade ensangüentada! Ela está toda cheia de mentiras e de rapina! da presa não há fim!");
    b->dados[NAUM].capitulos[3].versos[2] = wxT("Eis o estrépito do açoite, e o estrondo das rodas, os cavalos que curveteiam e os carros que saltam;");
    b->dados[NAUM].capitulos[3].versos[3] = wxT("o cavaleiro que monta, a espada rutilante, a lança reluzente, a, multidão de mortos, o montão de cadáveres, e defuntos inumeráveis; tropeçam nos cadáveres;");
    b->dados[NAUM].capitulos[3].versos[4] = wxT("tudo isso por causa da multidão dos adultérios, da meretriz formosa, da mestra das feitiçarias, que vende nações por seus deleites, e famílias pelas suas feitiçarias.");
    b->dados[NAUM].capitulos[3].versos[5] = wxT("Eis que eu estou contra ti, diz o Senhor dos exércitos; e levantarei as tuas fraldas sobre a tua face; e às nações mostrarei a tua nudez, e seus reinos a tua vergonha.");
    b->dados[NAUM].capitulos[3].versos[6] = wxT("Lançarei sobre ti imundícias e te tratarei com desprezo, e te porei como espetáculo.");
    b->dados[NAUM].capitulos[3].versos[7] = wxT("E há de ser todos os que te virem fugirão de ti, e dirão: Nínive esta destruída; quem terá compaixão dela? Donde te buscarei consoladores?");
    b->dados[NAUM].capitulos[3].versos[8] = wxT("És tu melhor do que Tebas, que se sentava à beira do Nilo, cercada de águas, tendo por baluarte o mar, e as águas por muralha,");
    b->dados[NAUM].capitulos[3].versos[9] = wxT("Etiópia e Egito eram a sua força, que era inesgotável; Pute e Líbia eram teus aliados.");
    b->dados[NAUM].capitulos[3].versos[10] = wxT("Todavia ela foi levada, foi para o cativeiro; também os seus pequeninos foram despedaçados nas entradas de todas as ruas, e sobre os seus nobres lançaram sortes, e todos os seus grandes foram presos em grilhões.");
    b->dados[NAUM].capitulos[3].versos[11] = wxT("Tu também serás embriagada, e ficarás escondida; e buscarás um refúgio do inimigo.");
    b->dados[NAUM].capitulos[3].versos[12] = wxT("Todas as tuas fortalezas serão como figueiras com figos temporãos; sendo eles sacudidos, caem na boca do que os há de comer.");
    b->dados[NAUM].capitulos[3].versos[13] = wxT("Eis que as tuas tropas no meio de ti são como mulheres; as portas da tua terra estão de todo abertas aos teus inimigos; o fogo consome os teus ferrolhos.");
    b->dados[NAUM].capitulos[3].versos[14] = wxT("Tira água para o tempo do cerco; reforça as tuas fortalezas; entra no lodo, pisa o barro, pega na forma para os tijolos.");
    b->dados[NAUM].capitulos[3].versos[15] = wxT("O fogo ali te consumirá; a espada te exterminará; ela te devorará como a locusta. Multiplica-te como a locusta, multiplica-te como o gafanhoto.");
    b->dados[NAUM].capitulos[3].versos[16] = wxT("Multiplicaste os teus negociantes mais do que as estrelas do céu; a locusta estende as asas e sai voando.");
    b->dados[NAUM].capitulos[3].versos[17] = wxT("Os teus príncipes são como os gafanhotos, e os teus chefes como enxames de gafanhotos, que se acampam nas sebes nos dias de frio; em subindo o sol voam, e não se sabe o lugar em que estão.");
    b->dados[NAUM].capitulos[3].versos[18] = wxT("Os teus pastores dormitam, ó rei da Assíria; os teus nobres dormem, o teu povo está espalhado pelos montes, sem que haja quem o ajunte.");
    b->dados[NAUM].capitulos[3].versos[19] = wxT("Não há cura para a tua ferida; a tua chaga é grave. Todos os que ouvirem a tua fama baterão as palmas sobre ti; porque, sobre quem não tem passado continuamente a tua malícia?");

}
